#include <stdio.h>
#include <stdlib.h>

#define MAX_GUESSES 10
#define SECRET_NUMBER 7

int main(void) {
    int guesses[MAX_GUESSES];
    char responses[MAX_GUESSES];
    int score = 0;
    int guess_count = 0;

    printf("Welcome to the Number Guessing Game!\n");
    printf("Guess a number between 1 and 10.\n");

    while (guess_count < MAX_GUESSES) {
        int guess;
        char response;

        printf("Enter your guess: ");
        scanf("%d", &guess);
        getchar(); // Consume newline character

        guesses[guess_count] = guess;

        if (guess == SECRET_NUMBER) {
            score += 10 - guess_count;
            break;
        } else {
            printf("Wrong guess. Try again.\n");
            printf("Was the number higher (H) or lower (L)? ");
            scanf("%c", &response);
            responses[guess_count] = response;

            if ((response == 'H' && guess < SECRET_NUMBER) || 
                (response == 'L' && guess > SECRET_NUMBER)) {
                score -= 1;
            } else {
                printf("Invalid response. No score deduction.\n");
            }
        }

        guess_count++;
    }

    printf("Game Over!\n");
    printf("Your guesses: ");
    for (int i = 0; i < guess_count; i++) {
        printf("%d ", guesses[i]);
    }
    printf("\n");

    printf("Your responses: ");
    for (int i = 0; i < guess_count; i++) {
        printf("%c ", responses[i]);
    }
    printf("\n");

    printf("Your final score: %d\n", score);

    return 0;
}

