        printf("Memory allocation failed\n");
        return 1;
    }

    for (int i = 0; i < num_players; i++) {
        scanf("%d", &choices[i]);
    }

    int tug_count = 0;
    int winner_index = -1;

    for (int i = 0; i < num_players; i++) {
        if (choices[i] == 1) {
            tug_count++;
            winner_index = i;
        }
    }

    printf("Tug\n");
    printf("Enter\n");

    if (tug_count > 1) {
        printf("No clear winner\n");
    } else if (tug_count == 0) {
        printf("No one tugged\n");
    } else {
        printf("Player %d is the winner\n", winner_index + 1);
    }

    free(choices);
    return 0;
}

